const fetch = require('node-fetch');
const baseUrl = process.env.ML_API_URL || 'http://ml-api:8503';
const token = process.env.ML_API_TOKEN || '';

const body = {};
if (typeof $id_insumo !== 'undefined' && $id_insumo) body.id_insumo = String($id_insumo);
if (typeof $insumo !== 'undefined' && $insumo) body.insumo = String($insumo);
if (typeof $fornecedor !== 'undefined' && $fornecedor) body.fornecedor = String($fornecedor);

if (!body.id_insumo && !body.insumo) {
    return JSON.stringify({ error: 'Informe id_insumo ou insumo para classificar o risco.' });
}

const headers = { 'Content-Type': 'application/json' };
if (token) headers['Authorization'] = `Bearer ${token}`;

try {
    const response = await fetch(`${baseUrl}/predict/insumo`, {
        method: 'POST',
        headers,
        body: JSON.stringify(body)
    });
    const text = await response.text();
    if (!response.ok) {
        return JSON.stringify({ error: text, status: response.status });
    }
    return text;
} catch (error) {
    console.error(error);
    return JSON.stringify({ error: String(error) });
}
